INSERT OR IGNORE INTO glossary (term, definition, category) VALUES ('Backup and Restore', 'DR strategy with highest RTO/RPO and lowest cost. Data backed up to DR region; entire infrastructure must be redeployed during disaster. Best for non-critical workloads or data protection only.', 'architecture');
INSERT OR IGNORE INTO glossary (term, definition, category) VALUES ('Pilot Light', 'DR strategy: core data continuously replicated to DR region, minimal infrastructure pre-provisioned (switched off). Scale up only when disaster strikes. Lower RTO than Backup & Restore, higher than Warm Standby.', 'architecture');
INSERT OR IGNORE INTO glossary (term, definition, category) VALUES ('Warm Standby', 'DR strategy: scaled-down but fully functional copy of production running in DR region at all times. Scale up to full capacity during failover. Faster RTO than Pilot Light, costs more.', 'architecture');
INSERT OR IGNORE INTO glossary (term, definition, category) VALUES ('Active/Active', 'Multi-Site DR strategy: full production workload running in multiple AWS Regions simultaneously. Traffic load-balanced across regions. Lowest RTO/RPO (near zero), highest cost. Also called Hot Standby.', 'architecture');
INSERT OR IGNORE INTO glossary (term, definition, category) VALUES ('IaC', 'Infrastructure as Code — managing and provisioning infrastructure through machine-readable configuration files (e.g. CloudFormation, Terraform) instead of manual processes. Enables repeatable, version-controlled deployments.', 'architecture');
INSERT OR IGNORE INTO glossary (term, definition, category) VALUES ('Blue/Green deployment', 'Deployment strategy with two identical environments (Blue = current, Green = new). Traffic switched from Blue to Green after testing. Instant rollback by switching back. Zero downtime deployments.', 'architecture');
INSERT OR IGNORE INTO glossary (term, definition, category) VALUES ('Canary deployment', 'Gradual traffic shift to a new version — e.g. 5% of users get v2, 95% get v1. Monitor for errors, then increase percentage. Reduces blast radius of bad deployments.', 'architecture');
INSERT OR IGNORE INTO glossary (term, definition, category) VALUES ('Fan-out', 'Pattern where one SNS topic delivers messages to multiple SQS queues simultaneously. Decouples producers from consumers. E.g. one S3 upload event triggers 3 different Lambda functions via SNS→SQS.', 'architecture');
INSERT OR IGNORE INTO glossary (term, definition, category) VALUES ('Event-driven', 'Architecture pattern where services communicate by producing and consuming events, not direct calls. Services are loosely coupled. E.g. S3 upload → EventBridge → Lambda → SQS → EC2.', 'architecture');
INSERT OR IGNORE INTO glossary (term, definition, category) VALUES ('Idempotency', 'Property where an operation produces the same result regardless of how many times it is called. Critical for distributed systems — if a Lambda is retried, it should not double-process an order.', 'architecture');
INSERT OR IGNORE INTO glossary (term, definition, category) VALUES ('Elasticity', 'Ability to automatically scale resources UP during peak demand and scale DOWN when demand drops. Distinct from scalability (which just means ability to scale up). Elasticity = auto up + auto down.', 'architecture');
INSERT OR IGNORE INTO glossary (term, definition, category) VALUES ('Fault tolerance', 'Ability of a system to continue operating correctly despite the failure of one or more components. Achieved through redundancy (Multi-AZ, Multi-Region), circuit breakers, and graceful degradation.', 'architecture');
INSERT OR IGNORE INTO glossary (term, definition, category) VALUES ('Shared Responsibility Model', 'AWS is responsible for security OF the cloud (physical infra, hardware, hypervisor). Customer is responsible for security IN the cloud (data, OS patches, IAM config, application security, encryption).', 'architecture');
INSERT OR IGNORE INTO glossary (term, definition, category) VALUES ('Serverless', 'No servers to manage — AWS handles provisioning, scaling, patching. Pay only for what you use. Examples: Lambda (compute), Fargate (containers), DynamoDB (database), Aurora Serverless (DB), S3 (storage).', 'architecture');
INSERT OR IGNORE INTO glossary (term, definition, category) VALUES ('Microservices', 'Architecture where an application is broken into small, independent services each with a single responsibility. Services communicate via APIs or events. Each can be deployed, scaled, and updated independently.', 'architecture');
INSERT OR IGNORE INTO glossary (term, definition, category) VALUES ('Containerization', 'Packaging an application and all its dependencies into a portable container image. Containers run consistently across environments. Docker is the standard format; ECS and EKS orchestrate containers on AWS.', 'architecture');
INSERT OR IGNORE INTO glossary (term, definition, category) VALUES ('Cold start', 'Latency when Lambda creates a new execution environment from scratch (download code, initialize runtime). Adds 100ms–1s+ delay. Mitigated by Provisioned Concurrency (pre-warmed environments) or keeping functions warm.', 'compute');
INSERT OR IGNORE INTO glossary (term, definition, category) VALUES ('Provisioned Concurrency', 'Lambda feature that pre-initializes a specified number of execution environments, eliminating cold starts. Pay extra for pre-warmed capacity. Use for latency-sensitive production workloads.', 'compute');
INSERT OR IGNORE INTO glossary (term, definition, category) VALUES ('Reserved Concurrency', 'Sets the maximum concurrent executions for a specific Lambda function (throttles above this limit). Also guarantees that capacity is reserved — other functions cannot use it. Setting to 0 = disable function.', 'compute');
INSERT OR IGNORE INTO glossary (term, definition, category) VALUES ('Lambda Layer', 'A .zip archive containing libraries, runtime, or other dependencies shared across multiple Lambda functions. Reduces deployment package size. Up to 5 layers per function.', 'compute');
INSERT OR IGNORE INTO glossary (term, definition, category) VALUES ('Fargate', 'Serverless compute engine for containers — runs ECS tasks or EKS pods without managing EC2 instances. AWS manages the underlying infrastructure. Pay per vCPU and memory used by each task.', 'compute');
INSERT OR IGNORE INTO glossary (term, definition, category) VALUES ('Instance store', 'Ephemeral block storage physically attached to the EC2 host. Data is LOST when the instance stops, terminates, or the underlying host fails. High I/O performance but no persistence. NOT for databases or important data.', 'compute');
INSERT OR IGNORE INTO glossary (term, definition, category) VALUES ('EC2 Placement Group', 'Controls how EC2 instances are placed on physical hardware. Cluster = same rack, low latency HPC. Spread = different racks, max resilience. Partition = groups on separate partitions for large distributed apps.', 'compute');
INSERT OR IGNORE INTO glossary (term, definition, category) VALUES ('Spot interruption', 'AWS can reclaim Spot Instances with 2-minute warning when capacity is needed. Applications must handle interruption gracefully. Use Spot for fault-tolerant, stateless, or checkpointable workloads.', 'compute');
INSERT OR IGNORE INTO glossary (term, definition, category) VALUES ('ARN', 'Amazon Resource Name — unique identifier for every AWS resource. Format: arn:partition:service:region:account-id:resource. Example: arn:aws:s3:::my-bucket. Used in IAM policies to specify exact resources.', 'services');
INSERT OR IGNORE INTO glossary (term, definition, category) VALUES ('Principal', 'Entity that can make requests to AWS: IAM user, IAM role, AWS service (e.g. Lambda), federated user, or AWS account. Specified in resource-based policies to define WHO can access the resource.', 'services');
INSERT OR IGNORE INTO glossary (term, definition, category) VALUES ('Identity-based policy', 'IAM policy attached to an IAM identity (user, group, role). Defines what actions that identity can perform on which resources. Most common policy type. Can be AWS managed, customer managed, or inline.', 'services');
INSERT OR IGNORE INTO glossary (term, definition, category) VALUES ('Resource-based policy', 'IAM policy attached to a resource (S3 bucket, SQS queue, KMS key, Lambda). Defines who can access the resource and what they can do. Enables cross-account access without requiring role assumption.', 'services');
INSERT OR IGNORE INTO glossary (term, definition, category) VALUES ('Permissions boundary', 'IAM managed policy that sets the MAXIMUM permissions an IAM entity (user or role) can have. Even if identity-based policies grant more, the boundary caps it. Does not grant permissions by itself.', 'services');
INSERT OR IGNORE INTO glossary (term, definition, category) VALUES ('Managed policy', 'Standalone IAM policy that can be attached to multiple users, groups, or roles. AWS managed = created by AWS (e.g. AdministratorAccess). Customer managed = created by you. Easier to reuse and update than inline.', 'services');
INSERT OR IGNORE INTO glossary (term, definition, category) VALUES ('Inline policy', 'IAM policy embedded directly into one specific user, group, or role. Not reusable. Deleted when the entity is deleted. Use sparingly — managed policies are preferred for maintainability.', 'services');
INSERT OR IGNORE INTO glossary (term, definition, category) VALUES ('Trust policy', 'Resource-based policy on an IAM role that defines which principals (services, accounts, users) can ASSUME the role. Every role has exactly one trust policy. Example: allow EC2 service to assume the role.', 'services');
INSERT OR IGNORE INTO glossary (term, definition, category) VALUES ('OU', 'Organizational Unit — a container for AWS accounts within AWS Organizations. SCPs can be applied to OUs to restrict all accounts within. OUs can be nested. Management account is at the root.', 'services');
INSERT OR IGNORE INTO glossary (term, definition, category) VALUES ('Permission denied', 'When IAM evaluation results in Deny. Explicit Deny always overrides Allow. A missing Allow = implicit Deny. Order: explicit Deny → SCP limit → permissions boundary → resource policy → identity policy.', 'services');
INSERT OR IGNORE INTO glossary (term, definition, category) VALUES ('ENI', 'Elastic Network Interface — virtual network card that can be attached to EC2 instances. Each has private IP, optionally public IP, MAC address, security groups. Multiple ENIs per instance for multi-subnet or failover.', 'networking');
INSERT OR IGNORE INTO glossary (term, definition, category) VALUES ('PrivateLink', 'AWS technology powering Interface VPC Endpoints. Creates private connectivity to AWS services or third-party services via ENIs in your VPC. Traffic never leaves AWS network. Used by all Interface endpoints.', 'networking');
INSERT OR IGNORE INTO glossary (term, definition, category) VALUES ('Anycast', 'Routing method where the same IP address is announced from multiple locations simultaneously. Client traffic automatically routed to the nearest location. Used by AWS Global Accelerator — traffic goes to nearest AWS edge.', 'networking');
INSERT OR IGNORE INTO glossary (term, definition, category) VALUES ('Egress', 'Traffic flowing OUT of your network or VPC to the internet or another network. Egress charges apply when data leaves AWS. NAT Gateway, Internet Gateway, and Direct Connect all handle egress traffic.', 'networking');
INSERT OR IGNORE INTO glossary (term, definition, category) VALUES ('Ingress', 'Traffic flowing INTO your network or VPC from the internet or another network. Security groups and NACLs control ingress. No AWS charge for ingress data transfer.', 'networking');
INSERT OR IGNORE INTO glossary (term, definition, category) VALUES ('FQDN', 'Fully Qualified Domain Name — complete domain name specifying exact location in DNS hierarchy. Example: my-alb-1234567890.us-east-1.elb.amazonaws.com. Alias records in Route 53 can point to FQDNs.', 'networking');
INSERT OR IGNORE INTO glossary (term, definition, category) VALUES ('Latency', 'Time delay between a request being sent and the response being received. Affected by geographic distance, network congestion, processing time. Reduce with: CloudFront, Global Accelerator, multi-region deployments.', 'networking');
INSERT OR IGNORE INTO glossary (term, definition, category) VALUES ('Throughput', 'Amount of data transferred per unit of time (MB/s, Gbps) or records processed per second. Higher throughput = more capacity. EBS st1 optimized for throughput; EBS io2 optimized for IOPS (random I/O).', 'networking');
INSERT OR IGNORE INTO glossary (term, definition, category) VALUES ('Pre-signed URL', 'Time-limited URL that grants temporary access to a private S3 object without requiring AWS credentials. Generated using AWS SDK with an expiry time (max 7 days). Used to share private files securely with external users.', 'storage');
INSERT OR IGNORE INTO glossary (term, definition, category) VALUES ('S3 Versioning', 'S3 feature that preserves every version of an object. When an object is overwritten or deleted, the previous version is retained. Enables recovery from accidental deletes or overwrites. Required for S3 Object Lock.', 'storage');
INSERT OR IGNORE INTO glossary (term, definition, category) VALUES ('S3 Lifecycle Policy', 'Automated rules to transition S3 objects between storage classes or expire (delete) them after a defined period. Example: transition to Glacier after 30 days, delete after 1 year. Reduces storage costs automatically.', 'storage');
INSERT OR IGNORE INTO glossary (term, definition, category) VALUES ('S3 Transfer Acceleration', 'Speeds up S3 uploads by routing traffic through CloudFront edge locations instead of directly to S3. Data enters AWS network at the nearest edge point. Useful for large file uploads from distant locations.', 'storage');
INSERT OR IGNORE INTO glossary (term, definition, category) VALUES ('SRR', 'Same-Region Replication — automatically copies S3 objects between buckets in the SAME region. Use for: compliance (separate account copy), log aggregation, live replicas for test environments.', 'storage');
INSERT OR IGNORE INTO glossary (term, definition, category) VALUES ('EBS Snapshot', 'Point-in-time backup of an EBS volume stored in S3 (managed by AWS). Incremental — only changed blocks since last snapshot are saved. Can be used to create new volumes or copy to other regions.', 'storage');
INSERT OR IGNORE INTO glossary (term, definition, category) VALUES ('DAX', 'DynamoDB Accelerator — fully managed in-memory cache for DynamoDB. Microsecond read latency (vs millisecond for DynamoDB). Drop-in compatible, no application code changes. Only for READ caching.', 'database');
INSERT OR IGNORE INTO glossary (term, definition, category) VALUES ('TTL', 'Time To Live — DynamoDB feature that auto-deletes items after a specified timestamp. No extra cost. Items expired within ~48 hours. Useful for session data, temp records, log expiry. Does NOT consume write capacity.', 'database');
INSERT OR IGNORE INTO glossary (term, definition, category) VALUES ('DLQ', 'Dead Letter Queue — SQS queue that receives messages which failed processing after the maximum number of retries (maxReceiveCount). Used for debugging, manual reprocessing, alerting. Prevents poison-pill messages blocking the queue.', 'database');
INSERT OR IGNORE INTO glossary (term, definition, category) VALUES ('FIFO Queue', 'First-In-First-Out SQS queue. Guarantees: (1) exact ordering of messages, (2) exactly-once processing. Max 300 transactions/second (3,000 with batching). Use when order matters (e.g. financial transactions, sequential steps).', 'database');
INSERT OR IGNORE INTO glossary (term, definition, category) VALUES ('NLB', 'Network Load Balancer — Layer 4 (TCP/UDP) load balancer. Handles millions of requests per second with ultra-low latency. Has static IP per AZ. Use for: non-HTTP traffic, static IP requirement, extreme performance needs.', 'networking');
INSERT OR IGNORE INTO glossary (term, definition, category) VALUES ('CLB', 'Classic Load Balancer — legacy (Layer 4 + Layer 7). Use ALB or NLB instead for new deployments. Still used for EC2-Classic or very old apps.', 'networking');
INSERT OR IGNORE INTO glossary (term, definition, category) VALUES ('Target Group', 'ALB/NLB routing destination — a group of registered targets (EC2 instances, IPs, Lambda functions, other ALBs). Health checks run against each target. Listener rules route traffic to specific target groups by path/host/header.', 'networking');